mapper.select:
select id, pipeline_instance_id, step_code, stage_code, run_seq, step_status, input_summary, output_summary, error_code, error_message, error_key, error_args, retry_count, duration_ms, started_at, finished_at from batch.pipeline_step_run where 1 = 1
and pipeline_instance_id = #{pipelineInstanceId}
and step_code = #{stepCode}
and stage_code = #{stageCode}
and step_status = #{stepStatus}
order by pipeline_instance_id desc, id desc
limit #{pageRequest.pageSize} offset (#{pageRequest.pageNo} - 1) * #{pageRequest.pageSize}

select count(1)
from batch.pipeline_step_run
where 1 = 1

    and pipeline_instance_id = #{pipelineInstanceId}


    and step_code = #{stepCode}


    and stage_code = #{stageCode}


    and step_status = #{stepStatus}
